num_gpus = 8
script_filenames = [f"run_gpu_{i}.sh" for i in range(num_gpus)]

# Initialize files
files = [open(fname, "w") for fname in script_filenames]
try:
    for i, cmd in enumerate(commands_long):
        gpu_id = i % num_gpus
        if i % num_gpus == 0:
            files[gpu_id].write("#!/bin/bash\n")
        full_cmd = f"OMP_NUM_THREADS=8 CUDA_VISIBLE_DEVICES={gpu_id} mpirun -np 1 --bind-to none --allow-run-as-root {cmd}\n"
        files[gpu_id].write(full_cmd)
finally:
    for f in files:
        f.close()

# Make scripts executable
import os
for fname in script_filenames:
    os.chmod(fname, 0o755)

print("Scripts written:")
for fname in script_filenames:
    print(f"  {fname}")

# Create launch script
with open("launch_all.sh", "w") as f:
    f.write("#!/bin/bash\n")
    for fname in script_filenames:
        f.write(f"./{fname} &\n")
    f.write("wait\n")
os.chmod("launch_all.sh", 0o755)

print("\nTo launch all scripts, run:")
print("  ./launch_all.sh")